// Format ALL CRM contacts for Lusha Bulk Enrichment API
const items = $input.all();
let contactIdCounter = 1;

const contacts = items
  .filter(item => item.json.properties?.email)
  .map(item => ({
    contactId: String(contactIdCounter++),
    email: item.json.properties.email
  }));

const payload = {
  contacts,
  metadata: {}
};

return [{ json: { contactsPayload: JSON.stringify(payload) } }];

// Compare bulk-enriched Lusha data with CRM records
// Match by email to detect job/company changes
const items = $input.all();
const crmContacts = $('Get CRM Contacts').all();

// Build email → CRM record lookup
const crmByEmail = {};
for (const c of crmContacts) {
  const email = (c.json.properties?.email || '').toLowerCase();
  if (email) crmByEmail[email] = c.json;
}

const results = [];
for (const item of items) {
  const lusha = item.json;
  const email = (lusha.primaryEmail || '').toLowerCase();
  const crm = crmByEmail[email] || {};

  const currentTitle = (crm.properties?.jobtitle || '').toLowerCase();
  const currentCompany = (crm.properties?.company || '').toLowerCase();
  const newTitle = (lusha.jobTitle || '').toLowerCase();
  const newCompany = (lusha.companyName || '').toLowerCase();

  const changes = [];
  if (newCompany && currentCompany && newCompany !== currentCompany) {
    changes.push({ field: 'company', from: crm.properties?.company, to: lusha.companyName });
  }
  if (newTitle && currentTitle && newTitle !== currentTitle) {
    changes.push({ field: 'jobTitle', from: crm.properties?.jobtitle, to: lusha.jobTitle });
  }

  results.push({
    json: {
      contactId: crm.id || '',
      email: crm.properties?.email || lusha.primaryEmail,
      firstName: crm.properties?.firstname || lusha.firstName,
      lastName: crm.properties?.lastname || lusha.lastName,
      hasChanges: changes.length > 0,
      changes,
      newJobTitle: lusha.jobTitle,
      newCompany: lusha.companyName,
      newSeniority: lusha.seniority,
      newPhone: lusha.primaryPhone,
      checkedAt: new Date().toISOString()
    }
  });
}

return results;
